/**
 * @param {MxObject[]} processTimers
 * @returns {Promise.<MxObject[]>}
 */
export async function JS_Sort_ProcessTimers(processTimers) {
	// BEGIN USER CODE
	if (!Array.isArray(processTimers)) {
        console.error("Expected a list of ProcessTimer objects, but got:", processTimers);
        return false;
    }

	const now = new Date();

    // Safely extract float values from timer fields
    function safeFloat(val) {
        return val != null && !isNaN(parseFloat(val)) ? parseFloat(val) : null;
    }

	// Compare helper
	function compareTimes(val1, val2, id1, id2) {
		if(val1 == val2) { // TimeToMax or TimeToMin same for both, then compare Ids
			const idA = BigInt("0x" + id1);
			const idB = BigInt("0x" + id2);
			return idA > idB ? 1 : -1;
		}

		const overdue1 = val1 >= 0;   // '+' means overdue
		const overdue2 = val2 >= 0;

		if (overdue1 && overdue2) {
			// Both overdue → bigger first
			return val2 - val1;
		}
		if (!overdue1 && !overdue2) {
			// Both not overdue → closer to zero first
			return Math.abs(val1) - Math.abs(val2);
		}

		// One overdue, one not → overdue wins
		return overdue1 ? -1 : 1;
	}

	processTimers.sort((timerA, timerB) => {
		const timerAProcessTimerId = timerA.get("TimerId");
		const timerBProcessTimerId = timerB.get("TimerId");

		const timerAStartTime = new Date(timerA.get("StartTimeGMT"));
		const timerAElapsedTime = (now - timerAStartTime) / (1000 * 60 * 60 * 24);

		const timerBStartTime = new Date(timerB.get("StartTimeGMT"));
		const timerBElapsedTime = (now - timerBStartTime) / (1000 * 60 * 60 * 24);

		const timerAMinTime = safeFloat(timerA.get("MinTime"));
		const timerAMaxTime = safeFloat(timerA.get("MaxTime"));
		const timerATimeToMax = timerAMaxTime != null ? -(timerAMaxTime - timerAElapsedTime) : null;
		const timerATimeToMin = timerAMinTime != null ? -(timerAMinTime - timerAElapsedTime) : null;

		const timerBMinTime = safeFloat(timerB.get("MinTime"));
		const timerBMaxTime = safeFloat(timerB.get("MaxTime"));		
		const timerBTimeToMax = timerBMaxTime != null ? -(timerBMaxTime - timerBElapsedTime) : null;		
		const timerBTimeToMin = timerBMinTime != null ? -(timerBMinTime - timerBElapsedTime) : null;
	
		// --- Rule 1: Always prioritize TimeToMax ---
		if (timerATimeToMax != null || timerBTimeToMax != null) {
			if (timerATimeToMax == null) return 1;   // only B has Max → B first
			if (timerBTimeToMax == null) return -1;  // only A has Max → A first
			return compareTimes(timerATimeToMax, timerBTimeToMax, timerAProcessTimerId, timerBProcessTimerId);
		}

		// --- Rule 2: Fallback to TimeToMin ---
		if (timerATimeToMin != null || timerBTimeToMin != null) {
			if (timerATimeToMin == null) return 1;   // only B has Min → B first
			if (timerBTimeToMin == null) return -1;  // only A has Min → A first
			return compareTimes(timerATimeToMin, timerBTimeToMin, timerAProcessTimerId, timerBProcessTimerId);
		}
	});

	return processTimers;
	// END USER CODE
}
